// ── NAV ──
const PGS={home:'pg-home',est:'pg-est',map:'pg-map',check:'pg-check',cmp:'pg-cmp',hist:'pg-hist'};
function go(id,btn){
  // Сбрасываем страницы при уходе
  if(id !== 'est')   estReset();
  if(id !== 'check') checkReset();
  if(id !== 'cmp')   cmpReset();

  Object.values(PGS).forEach(p=>{const e=document.getElementById(p);if(e)e.classList.remove('on')});
  document.querySelectorAll('.nl').forEach(l=>l.classList.remove('on'));
  document.querySelectorAll('.mob-tab-btn').forEach(b=>b.classList.remove('on'));
  document.getElementById(PGS[id])?.classList.add('on');
  if(btn&&btn.classList) btn.classList.add('on');

  // Синхронизируем tab bar
  const PG_ORDER = ['home','est','map','check','cmp','hist'];
  const idx = PG_ORDER.indexOf(id);
  const tabBtns = document.querySelectorAll('.mob-tab-btn');
  if(tabBtns[idx]) tabBtns[idx].classList.add('on');

  if(id==='map')setTimeout(function(){
    initLeafMap();
    if(leafMap){leafMap.invalidateSize();renderHeat();leafMap.fitBounds(L.geoJSON(DISTRICTS_GJ).getBounds(),{padding:[30,30]});loadDBPoints();}
  },150);
  if(id==='cmp')setTimeout(drawRadar,80);
  if(id==='hist')setTimeout(histOpen,50);
}

function mobGo(id, btn){
  const PG_ORDER = ['home','est','map','check','cmp','hist'];
  const idx = PG_ORDER.indexOf(id);
  const desktopBtn = document.querySelectorAll('.nl')[idx] || null;
  go(id, desktopBtn);
  document.querySelectorAll('.mob-tab-btn').forEach(b=>b.classList.remove('on'));
  btn.classList.add('on');
}

function estReset(){
  // Форма
  const g = id => document.getElementById(id);
  const inp = g('e_d_input');
  if(inp){ inp.value = ''; }
  if(g('e_lat')) g('e_lat').value = '';
  if(g('e_lon')) g('e_lon').value = '';
  if(g('e_ot'))  g('e_ot').selectedIndex = 0;
  if(g('e_bt'))  g('e_bt').selectedIndex = 0;
  if(g('e_a'))   g('e_a').value  = '';
  if(g('e_r'))   g('e_r').value  = '';
  if(g('e_fl'))  g('e_fl').value = '';
  if(g('e_k'))   g('e_k').value  = '';
  if(g('districtDropdown')) g('districtDropdown').style.display = 'none';

  // Результат
  const rp = g('r_price');
  if(rp){ rp.style.color = 'rgba(255,255,255,.22)'; rp.innerHTML = '—'; }
  if(g('r_sqm'))   g('r_sqm').textContent  = '';
  const rangeEl = g('r_range');
  if(rangeEl){ rangeEl.innerHTML = ''; rangeEl.style.display = 'none'; }
  if(g('r_verdict'))    g('r_verdict').style.display    = 'none';
  if(g('r_hint'))       g('r_hint').style.display       = 'flex';
  if(g('factors_list')) g('factors_list').innerHTML =
    '<div style="font-size:13px;color:var(--ink3);padding:8px 0">Нажмите «Рассчитать» чтобы увидеть факторы</div>';

  // Похожие квартиры
  if(g('similarCard'))  g('similarCard').style.display  = 'none';
  if(g('similarList'))  g('similarList').innerHTML      = '';
  g('estWrap')?.classList.remove('has-similar');
}

// ── ESTIMATE ──
function checkReset(){
  const g = id => document.getElementById(id);
  if(g('c_d_input'))  g('c_d_input').value  = '';
  if(g('c_lat'))      g('c_lat').value       = '';
  if(g('c_lon'))      g('c_lon').value       = '';
  if(g('c_a'))        g('c_a').value         = '';
  if(g('c_r'))        g('c_r').value         = '';
  if(g('c_fl'))       g('c_fl').value        = '';
  if(g('c_k'))        g('c_k').value         = '';
  if(g('c_b'))        g('c_b').selectedIndex = 0;
  if(g('c_ot'))       g('c_ot').selectedIndex= 0;
  if(g('c_p'))        g('c_p').value         = '';
  if(g('checkDistrictDropdown')) g('checkDistrictDropdown').style.display = 'none';
  if(g('checkHint'))   g('checkHint').style.display   = 'block';
  if(g('checkResult')) g('checkResult').style.display = 'none';
  if(g('checkLoader')) g('checkLoader').style.display = 'none';
  if(g('checkError'))  g('checkError').style.display  = 'none';
}


