let _districtSelected = false;
let _ddHighlight = -1;

function districtSearch(query){
  const dd = document.getElementById('districtDropdown');
  const q  = query.trim().toLowerCase();

  const matches = q
    ? NSO_DISTRICTS.filter(d => d.name.toLowerCase().includes(q)).slice(0, 15)
    : NSO_DISTRICTS;  // показываем ВСЕ районы при пустом поле

  if(!matches.length){ dd.style.display = 'none'; return; }

  _ddHighlight = -1;
  dd.innerHTML = matches.map((d, i) =>
    `<div class="dd-item" data-i="${i}"
      onclick="districtSelect('${d.name.replace(/'/,"\\'")}',${d.lat},${d.lon})"
      onmouseover="ddHighlight(${i})"
      style="padding:10px 14px;cursor:pointer;font-size:13px;color:var(--ink);
             border-bottom:1px solid #f5f5f5">
      ${d.name}
    </div>`
  ).join('');
  dd.style.display = 'block';
  dd._matches = matches;
}

function ddHighlight(i){
  _ddHighlight = i;
  document.querySelectorAll('.dd-item').forEach((el, j) => {
    el.style.background = j === i ? '#f0faf6' : '';
  });
}

function districtKeydown(e){
  const dd = document.getElementById('districtDropdown');
  const items = dd.querySelectorAll('.dd-item');
  if(!items.length) return;
  if(e.key === 'ArrowDown'){
    e.preventDefault();
    _ddHighlight = Math.min(_ddHighlight + 1, items.length - 1);
    ddHighlight(_ddHighlight);
  } else if(e.key === 'ArrowUp'){
    e.preventDefault();
    _ddHighlight = Math.max(_ddHighlight - 1, 0);
    ddHighlight(_ddHighlight);
  } else if(e.key === 'Enter' && _ddHighlight >= 0){
    e.preventDefault();
    items[_ddHighlight].click();
  } else if(e.key === 'Escape'){
    dd.style.display = 'none';
  }
}

function districtSelect(name, lat, lon){
  document.getElementById('e_d_input').value = name;
  document.getElementById('e_lat').value = lat;
  document.getElementById('e_lon').value = lon;
  document.getElementById('districtDropdown').style.display = 'none';
  _districtSelected = true;
}

// Закрываем дропдаун при клике вне
document.addEventListener('click', e => {
  if(!e.target.closest('#e_d_input') && !e.target.closest('#districtDropdown')){
    document.getElementById('districtDropdown').style.display = 'none';
  }
});

// ── ПОХОЖИЕ КВАРТИРЫ ─────────────────────────────────────────────────────
async function loadSimilar(lat, lon, area, rooms, modelPrice){
  const card = document.getElementById('similarCard');
  const list = document.getElementById('similarList');
  card.style.display = 'none';
  document.getElementById('estWrap')?.classList.remove('has-similar');

  try {
    const resp = await fetch('/similar', {
      method: 'POST',
      headers: {'Content-Type':'application/json'},
      body: JSON.stringify({geo_lat: lat, geo_lon: lon, area, rooms})
    });
    const data = await resp.json();
    if(!data.items || !data.items.length) return;

    const fmt = n => (+n).toLocaleString('ru');
    list.innerHTML = data.items.map(it => {
      const diff    = it.price - modelPrice;
      const diffPct = Math.round(diff / modelPrice * 100);
      const diffCol = diff > 0 ? '#c0392b' : '#1a6e4a';
      const diffSign = diff > 0 ? '+' : '';
      return `
      <div style="padding:12px 0;border-bottom:1px solid #f0f2f5">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px">
          <div>
            <div style="font-size:13px;font-weight:700;color:var(--ink)">
              ${it.area} м² · ${it.rooms} комн. · эт. ${it.level}
            </div>
            <div style="font-size:11px;color:#637b95;margin-top:2px">
              ${it.bt} · ${it.ot} · ${fmt(it.ppm)} ₽/м²
            </div>
          </div>
          <div style="text-align:right;flex-shrink:0">
            <div style="font-size:14px;font-weight:900;color:var(--ink)">${fmt(it.price)} ₽</div>
            <div style="font-size:11px;font-weight:700;color:${diffCol}">${diffSign}${diffPct}% к модели</div>
          </div>
        </div>
      </div>`;
    }).join('');

    card.style.display = 'block';
    // Небольшая задержка чтобы браузер пересчитал grid
    requestAnimationFrame(() => {
      document.getElementById('estWrap')?.classList.add('has-similar');
    });
  } catch(e){ console.warn('similar error:', e); }
}

async function doEstimate(){
  // Валидация
  const geo_lat_raw = document.getElementById('e_lat').value;
  const geo_lon_raw = document.getElementById('e_lon').value;
  if(!geo_lat_raw || !geo_lon_raw){
    const inp = document.getElementById('e_d_input');
    inp.focus();
    inp.placeholder = '⚠ Выберите район из списка';
    inp.style.borderColor = 'var(--red2)';
    inp.style.boxShadow   = '0 0 0 3px rgba(192,57,43,.15)';
    const reset = () => {
      inp.style.borderColor = '';
      inp.style.boxShadow   = '';
      inp.placeholder = 'Начните вводить район…';
      inp.removeEventListener('input', reset);
    };
    inp.addEventListener('input', reset);
    setTimeout(reset, 3000);
    return;
  }

  const area    = +document.getElementById('e_a').value   || 54;
  const rooms   = +document.getElementById('e_r').value   || 2;
  const kitchen = +document.getElementById('e_k').value   || 10;
  const level   = +document.getElementById('e_fl').value  || 5;
  const levels  = +document.getElementById('e_fls').value || 9;
  const year    = +document.getElementById('e_y').value   || 2019;
  const month   = +document.getElementById('e_mo').value  || 6;
  const geo_lat = +geo_lat_raw || 54.99;
  const geo_lon = +geo_lon_raw || 82.90;
  const obj_type= +document.getElementById('e_ot').value  || 1;
  const bld_type= +document.getElementById('e_bt').value  || 1;
  const ltl = levels > 0 ? level / levels : 0.5;
  const atr = rooms  > 0 ? area  / rooms  : area;

  document.getElementById('r_price').innerHTML =
    '<span style="font-size:20px;color:rgba(255,255,255,.5)">Считаем...</span>';

  let data;
  try {
    const resp = await fetch('/predict', {
      method: 'POST',
      headers: {'Content-Type':'application/json'},
      body: JSON.stringify({
        geo_lat, geo_lon, building_type: bld_type,
        level, levels, rooms, area, kitchen_area: kitchen,
        object_type: obj_type, level_to_levels: ltl,
        year, month, area_to_rooms: atr,
        district_name: document.getElementById('e_d_input')?.value || '',
      })
    });
    data = await resp.json();
    if(data.error) throw new Error(data.error);
  } catch(e) {
    document.getElementById('r_price').innerHTML =
      '<span style="font-size:14px;color:#e05252">Ошибка: ' + e.message + '</span>';
    return;
  }

  // Цена
  const rp = document.getElementById('r_price');
  rp.style.color = '';   // сбрасываем серый inline-стиль → CSS даёт белый
  rp.innerHTML = data.price.toLocaleString('ru') + ' <small>₽</small>';
  document.getElementById('r_sqm').textContent =
    '≈ ' + data.pricePerSqm.toLocaleString('ru') + ' ₽ за квадратный метр';
  const rangeEl = document.getElementById('r_range');
  rangeEl.innerHTML = '📊 Диапазон: ' + data.priceLow.toLocaleString('ru') +
    ' — ' + data.priceHigh.toLocaleString('ru') + ' ₽';
  rangeEl.style.display = 'block';

  // Показываем verdict
  document.getElementById('r_verdict').style.display = 'flex';

  // Скрываем подсказку-hint
  const hint = document.getElementById('r_hint');
  if(hint) hint.style.display = 'none';

  // Загружаем похожие квартиры
  loadSimilar(geo_lat, geo_lon, area, rooms, data.price);

  // Сегмент из Flask
  const seg = data.segment;
  const vd  = document.getElementById('r_verdict');
  if(vd && seg){
    vd.className = 'verdict-strip ' + seg.cls;
    document.getElementById('r_vt').textContent = seg.title;
    document.getElementById('r_vd').textContent = seg.desc;
    vd.querySelector('.vs-icon').textContent = seg.icon;
  }

  // Факторы из SHAP
  const fl = document.getElementById('factors_list');
  if(fl && data.factors && data.factors.length > 0){
    fl.innerHTML = data.factors.map(f => {
      const color = f.impact==='pos' ? 'var(--green2)' : f.impact==='neg' ? 'var(--red2)' : 'var(--blue2)';
      const tag   = f.impact==='pos'
        ? '<div class="fr-tag fr-pos">+' + f.pct + '% к цене</div>'
        : f.impact==='neg'
        ? '<div class="fr-tag fr-neg">' + f.pct + '% к цене</div>'
        : '<div class="fr-tag fr-neu">нейтрально</div>';
      return '<div class="factor-row">' +
        '<div class="fr-label">' + f.icon + ' ' + f.label + '</div>' +
        '<div class="fr-bar"><div class="fr-fill" style="width:' + f.bar + '%;background:' + color + '"></div></div>' +
        tag + '</div>';
    }).join('');
  }

  // Сохраняем в историю
  const districtName = document.getElementById('e_d')?.selectedOptions[0]?.text || 'Неизвестный р-н';
  const btSel = document.getElementById('e_bt');
  const otSel = document.getElementById('e_ot');
  histSave({
    source:      'estimate',
    district:    districtName,
    area, rooms, level, levels, year, month,
    kitchen:     kitchen,
    btype_name:  btSel?.selectedOptions[0]?.text || '—',
    otype_name:  otSel?.selectedOptions[0]?.text || '—',
    price:       data.price,
    price_sqm:   data.pricePerSqm,
    price_low:   data.priceLow,
    price_high:  data.priceHigh,
    verdict:     data.segment?.cls || 'ok',
    verdict_title: data.segment?.title || '',
    diff_pct:    null,
    listed:      0,
    // Нормализуем факторы /predict → единый формат для модалки
    factors: (data.factors || []).map(f => ({
      icon:      f.icon      || '📊',
      name:      f.label     || f.name  || '—',
      value:     '',
      shap_rub:  f.pct ? Math.round(f.pct / 100 * data.price) : 0,
      direction: f.impact === 'pos' ? 'pos' : 'neg',
      bar:       f.bar || 0,
    })),
  });
}



