let _cdHighlight = -1;

function checkDistrictSearch(query){
  const dd = document.getElementById('checkDistrictDropdown');
  const q  = query.trim().toLowerCase();
  const matches = q
    ? NSO_DISTRICTS.filter(d => d.name.toLowerCase().includes(q)).slice(0, 15)
    : NSO_DISTRICTS;
  if(!matches.length){ dd.style.display='none'; return; }
  _cdHighlight = -1;
  dd.innerHTML = matches.map((d, i) =>
    `<div class="dd-item" data-i="${i}"
      onclick="checkDistrictSelect('${d.name.replace(/'/,"\'")}',${d.lat},${d.lon})"
      onmouseover="cdHighlight(${i})"
      style="padding:10px 14px;cursor:pointer;font-size:13px;color:var(--ink);
             border-bottom:1px solid #f5f5f5">${d.name}</div>`
  ).join('');
  dd.style.display = 'block';
  dd._matches = matches;
}

function cdHighlight(i){
  _cdHighlight = i;
  document.querySelectorAll('#checkDistrictDropdown .dd-item').forEach((el,j) => {
    el.style.background = j===i ? '#f0faf6' : '';
  });
}

function checkDistrictKeydown(e){
  const dd = document.getElementById('checkDistrictDropdown');
  const items = dd.querySelectorAll('.dd-item');
  if(!items.length) return;
  if(e.key==='ArrowDown'){ e.preventDefault(); _cdHighlight=Math.min(_cdHighlight+1,items.length-1); cdHighlight(_cdHighlight); }
  else if(e.key==='ArrowUp'){ e.preventDefault(); _cdHighlight=Math.max(_cdHighlight-1,0); cdHighlight(_cdHighlight); }
  else if(e.key==='Enter'&&_cdHighlight>=0){ e.preventDefault(); items[_cdHighlight].click(); }
  else if(e.key==='Escape'){ dd.style.display='none'; }
}

