async function doCheck(){
  const el = id => document.getElementById(id);
  if(!el('c_a')) return;

  // Валидация района
  const geo_lat_raw = el('c_lat')?.value;
  const geo_lon_raw = el('c_lon')?.value;
  if(!geo_lat_raw || !geo_lon_raw){
    const inp = el('c_d_input');
    if(inp){
      inp.focus();
      inp.placeholder = '⚠ Выберите район из списка';
      inp.style.borderColor = 'var(--red2)';
      const reset = () => { inp.style.borderColor=''; inp.placeholder='Начните вводить район…'; inp.removeEventListener('input',reset); };
      inp.addEventListener('input', reset);
      setTimeout(reset, 3000);
    }
    return;
  }

  // Собираем параметры
  const geo_lat = parseFloat(geo_lat_raw);
  const geo_lon = parseFloat(geo_lon_raw);
  const area    = parseFloat(el('c_a').value)||42;
  const rooms   = parseInt(el('c_r').value)||2;
  const floor   = parseInt(el('c_fl').value)||5;
  const floors  = 9;   // среднее, не запрашиваем у пользователя
  const year    = 2010; // медианное значение датасета
  const kit     = parseFloat(el('c_k').value)||9;
  const btype   = parseInt(el('c_b').value)||1;
  const otype   = parseInt(el('c_ot').value)||1;
  const listed  = parseFloat(el('c_p').value)||0;

  // UI: показываем лоадер, скрываем hint
  if(el('checkHint')) el('checkHint').style.display = 'none';
  el('checkResult').style.display = 'none';
  el('checkError').style.display  = 'none';
  el('checkLoader').style.display = 'block';

  try {
    const resp = await fetch('/analyze', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({
        geo_lat, geo_lon,
        building_type: btype,
        level: floor, levels: floors,
        rooms, area,
        kitchen_area: kit,
        object_type: otype,
        year, month: 6,
        listed_price: listed,
        district_name: el('c_d_input')?.value || '',
      })
    });
    const d = await resp.json();
    if(d.error){ throw new Error(d.error); }

    el('checkLoader').style.display = 'none';
    el('checkResult').style.display = 'grid';

    // ── Вердикт ──────────────────────────────────────────────────
    const box = el('bvBox');
    const v   = d.verdict;
    box.className = 'bv2 ' +
      (v.status==='high'?'bv2-amber': v.status==='low'?'bv2-green':'bv2-ok');
    el('bv_ico').textContent   = v.icon;
    el('bv_title').textContent = v.title;
    el('bv_sub').textContent   = v.sub;

    const fmt = n => n.toLocaleString('ru') + ' ₽';
    el('bv_listed').textContent = listed>0 ? fmt(listed) : '—';
    el('bv_model').textContent  = fmt(d.model_price);
    el('bv_range').textContent  = fmt(d.price_low) + ' – ' + fmt(d.price_high);
    el('bv_sqm').textContent    = d.price_per_sqm.toLocaleString('ru') + ' ₽/м²';

    const diffEl = el('bv_diff');
    if(listed > 0){
      const sign = d.diff_rub >= 0 ? '+' : '';
      diffEl.textContent = sign + fmt(d.diff_rub) + ` (${sign}${d.diff_pct}%)`;
      diffEl.style.color = d.diff_rub>0 ? 'var(--red2)' : 'var(--green)';
    } else {
      diffEl.textContent = '—';
    }

    const sugRow = el('bv_suggest_row');
    if(d.suggest){
      sugRow.style.display = 'flex';
      el('bv_suggest').textContent = fmt(d.suggest);
    } else {
      sugRow.style.display = 'none';
    }

    // ── SHAP waterfall ────────────────────────────────────────────
    el('shap_base').textContent = d.base_value.toLocaleString('ru') + ' ₽';

    const wf = el('shapWaterfall');
    if(!d.factors || !d.factors.length){
      wf.innerHTML = '<p style="color:#637b95;font-size:13px">SHAP-данные недоступны (модель загружена без SHAP).</p>';
    } else {
      wf.innerHTML = d.factors.map(f => {
        const pos   = f.direction === 'pos';
        const color = pos ? '#1a6e4a' : '#c0392b';
        const bg    = pos ? '#e8f5f0' : '#fdf0ee';
        const sign  = pos ? '+' : '';
        const rub   = Math.abs(f.shap_rub).toLocaleString('ru');
        const arrow = pos ? '▲' : '▼';
        return `
        <div style="display:flex;align-items:center;gap:12px;padding:10px 0;border-bottom:1px solid #f0f2f5">
          <div style="font-size:20px;width:28px;text-align:center;flex-shrink:0">${f.icon}</div>
          <div style="flex:1;min-width:0">
            <div style="font-size:12px;font-weight:700;color:#1a1a2e;margin-bottom:2px">
              ${f.name}
              <span style="font-weight:400;color:#637b95;margin-left:6px">${f.value}</span>
            </div>
            <div style="background:#f0f2f5;border-radius:4px;height:6px;margin-top:5px;overflow:hidden">
              <div style="height:100%;width:${f.bar}%;background:${color};border-radius:4px;transition:width .4s"></div>
            </div>
          </div>
          <div style="text-align:right;flex-shrink:0;min-width:110px">
            <div style="font-size:13px;font-weight:800;color:${color}">${arrow} ${sign}${rub} ₽</div>
            <div style="font-size:10px;color:#637b95;margin-top:1px">${sign}${f.pct}% от цены</div>
          </div>
        </div>`;
      }).join('');
    }

    // Сохраняем в историю
    histSave({
      source:      'check',
      district:    el('c_d')?.selectedOptions[0]?.text || 'Неизвестный р-н',
      area:        parseFloat(el('c_a').value) || 42,
      rooms:       parseInt(el('c_r').value)   || 2,
      level:       parseInt(el('c_fl').value)  || 5,
      levels:      9,
      kitchen:     parseFloat(el('c_k').value) || 9,
      btype_name:  el('c_b')?.selectedOptions[0]?.text || '—',
      otype_name:  el('c_ot')?.selectedOptions[0]?.text || '—',
      price:       d.model_price,
      price_sqm:   d.price_per_sqm,
      price_low:   d.price_low,
      price_high:  d.price_high,
      listed:      listed,
      verdict:     d.verdict?.status || 'ok',
      verdict_title: d.verdict?.title || '',
      diff_pct:    d.diff_pct,
      diff_rub:    d.diff_rub,
      suggest:     d.suggest,
      factors:     d.factors || [],
    });

  } catch(e) {
    el('checkLoader').style.display = 'none';
    el('checkError').style.display  = 'block';
    el('checkError').textContent    = '⚠ Ошибка: ' + e.message;
  }
}


