function priceColor(p){
  if(p>=130)return{fill:'#1a6e4a',border:'#145238'};
  if(p>=90) return{fill:'#2e9e6e',border:'#1e7a52'};
  if(p>=65) return{fill:'#f5a623',border:'#c8820a'};
  return        {fill:'#e05252',border:'#b03030'};
}

// Центроид полигона
function centroid(geom){
  let coords = geom.type==='Polygon'
    ? geom.coordinates[0]
    : geom.coordinates[0][0];
  const n=coords.length;
  let lat=0,lon=0;
  coords.forEach(c=>{lon+=c[0];lat+=c[1];});
  return [lat/n, lon/n];
}

function renderHeat(){
  heatGroup.clearLayers();
    document.getElementById('mapLegend').style.display='block';

  // 1. Граница НСО (жирная синяя линия)
  L.geoJSON(NSO_BOUNDARY_GJ,{
    style:{color:'#1a3a6e',weight:3,fillOpacity:0,dashArray:null},
  }).addTo(heatGroup);

  // 2. Районы
  DISTRICTS_GJ.features.forEach(f=>{
    const p=f.properties, c=priceColor(p.price);
    const layer=L.geoJSON(f,{
      style:{color:c.border,fillColor:c.fill,fillOpacity:0.50,weight:1.5},
    });
    layer.bindTooltip(
      '<div style="text-align:center;font-family:Geologica,sans-serif;padding:4px">'+
      '<b>'+p.label+'</b><br>'+
      '<span style="font-size:16px;font-weight:900;color:'+c.fill+'">'+p.price+' тыс. ₽/м²</span></div>',
      {sticky:true}
    );
    layer.bindPopup(
      '<div style="min-width:180px;font-family:Geologica,sans-serif">'+
      '<b style="font-size:14px">'+p.label+'</b><br>'+
      '<span style="font-size:22px;font-weight:900;color:'+c.fill+'">'+p.price+' тыс. ₽/м²</span><br>'+
      '<span style="font-size:11px;color:#637b95">Средняя цена, 2018–2021 гг.</span></div>'
    );
    layer.on('mouseover',e=>e.target.setStyle({fillOpacity:0.75}));
    layer.on('mouseout', e=>e.target.setStyle({fillOpacity:0.50}));
    heatGroup.addLayer(layer);

    // 3. Постоянная подпись через permanent tooltip - всегда в центре полигона
    layer.bindTooltip('<b style="font-size:10px;font-weight:700;color:#1a1a2e;'+
      'text-shadow:0 0 4px #fff,0 0 4px #fff,0 0 4px #fff;font-family:Geologica,sans-serif">'+
      p.label+'</b>',{
      permanent: true,
      direction: 'center',
      className: 'district-label-tooltip',
      opacity: 1,
    });
  });
}

function initLeafMap(){
  if(mapReady)return;
  mapReady=true;
  // L уже в leaflet_bundle.js
  (function(){
    leafMap=L.map('leafmap',{center:[54.9,80.5],zoom:6,zoomControl:false});
// Custom zoom slider
const ZoomSlider = L.Control.extend({
  options: { position: 'topleft' },
  onAdd(map) {
    const c = L.DomUtil.create('div','zoom-slider-wrap');
    c.innerHTML = `
      <button class="zs-btn" id="zs-in">+</button>
      <div class="zs-track">
        <div class="zs-thumb" id="zs-thumb"></div>
      </div>
      <button class="zs-btn" id="zs-out">−</button>`;
    L.DomEvent.disableClickPropagation(c);

    const track = c.querySelector('.zs-track');
    const thumb = c.querySelector('#zs-thumb');
    const MIN=4, MAX=18;

    function updateThumb() {
      const pct = (map.getZoom()-MIN)/(MAX-MIN);
      thumb.style.top = (100 - pct*100).toFixed(1)+'%';
    }
    updateThumb();
    map.on('zoom', updateThumb);

    c.querySelector('#zs-in').onclick  = function(e){ e.stopPropagation(); map.setZoom(map.getZoom()+1,{animate:true}); };
    c.querySelector('#zs-out').onclick = function(e){ e.stopPropagation(); map.setZoom(map.getZoom()-1,{animate:true}); };

    // Drag thumb
    let dragging=false, startY=0, startZoom=0;
    thumb.addEventListener('mousedown', e=>{
      dragging=true; startY=e.clientY; startZoom=map.getZoom();
      e.preventDefault();
    });
    document.addEventListener('mousemove', e=>{
      if(!dragging) return;
      const trackH = track.getBoundingClientRect().height;
      const dy = startY - e.clientY;
      const dz = (dy/trackH)*(MAX-MIN);
      map.setZoom(Math.max(MIN,Math.min(MAX, startZoom+dz)), {animate:false});
    });
    document.addEventListener('mouseup',()=>dragging=false);

    // Click on track
    track.addEventListener('click', e=>{
      if(e.target===thumb) return;
      const rect = track.getBoundingClientRect();
      const pct  = 1-(e.clientY-rect.top)/rect.height;
      map.setZoom(MIN+pct*(MAX-MIN), {animate:true});
    });
    return c;
  }
});
new ZoomSlider().addTo(leafMap);
    L.tileLayer('https://tile2.maps.2gis.com/tiles?x={x}&y={y}&z={z}&v=1',{
      attribution:' ',maxZoom:18,
    }).addTo(leafMap);
    heatGroup=L.layerGroup().addTo(leafMap);
    dotGroup=L.layerGroup();
    
    renderHeat();
    loadDBPoints();
    // Remove blue outline on click
    leafMap.on('click', ()=>{
      document.querySelectorAll('path.leaflet-interactive').forEach(p=>{p.style.outline='none';p.setAttribute('tabindex','-1');});
    });
    leafMap.fitBounds(L.geoJSON(DISTRICTS_GJ).getBounds(),{padding:[30,30]});
    leafMap.invalidateSize();

    // Скрываем подписи на мелком масштабе
    leafMap.on('zoomend',()=>{
      if(leafMap.getZoom()<7) labelGroup.removeFrom(leafMap);
    });
  })();
}

async function renderDots(){
  if(!leafMap)return;
  heatGroup.clearLayers();
  dotGroup.clearLayers();
  if(leafMap.hasLayer(heatGroup))leafMap.removeLayer(heatGroup);
  document.getElementById('mapLegend').style.display='none';
  leafMap.setView([54.98,82.92],10);

  // Показываем лоадер
  const loader=document.createElement('div');
  loader.id='dotsLoader';
  loader.style.cssText='position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);z-index:1001;'+
    'background:rgba(255,255,255,.95);padding:14px 22px;border-radius:12px;font-size:14px;font-weight:600';
  loader.textContent='⏳ Загружаем объекты из базы...';
  document.getElementById('leafmap').appendChild(loader);

  try {
    const resp = await fetch('/map-points?n=800');
    const data = await resp.json();
    loader.remove();

    if(!data.points || data.points.length === 0) return;

    data.points.forEach(p => {
      // Цвет по цене
      const price = p.price || 0;
      const col = price > 5000000 ? '#1a6e4a'
                : price > 3000000 ? '#2e9e6e'
                : price > 2000000 ? '#f5a623'
                : '#e05252';

      const ppm = p.area > 0 ? Math.round(price / p.area) : 0;
      const tip = `<b>${(price/1e6).toFixed(2)} млн ₽</b><br>` +
        `${p.area} м² · ${ppm.toLocaleString('ru')} ₽/м²<br>` +
        `${p.rooms} комн. · кухня ${p.kit} м²<br>` +
        `${p.bt} · ${p.ot} · этаж ${p.level}`;

      L.circleMarker([p.lat, p.lon], {
        radius:      5,
        fillColor:   col,
        color:       '#fff',
        weight:      1,
        fillOpacity: 0.85,
      }).bindTooltip(tip, {sticky:true}).addTo(dotGroup);
    });

    dotGroup.addTo(leafMap);

    // Легенда для точек
    const leg = document.getElementById('mapLegend');
    if(leg){
      leg.style.display='block';
      leg.innerHTML=`
        <div style="font-size:11px;font-weight:700;color:var(--ink);margin-bottom:8px">Цена объекта</div>
        <div style="display:flex;align-items:center;gap:7px;margin-bottom:5px;font-size:11px"><span style="width:10px;height:10px;border-radius:50%;background:#1a6e4a;display:inline-block"></span>от 5 млн ₽</div>
        <div style="display:flex;align-items:center;gap:7px;margin-bottom:5px;font-size:11px"><span style="width:10px;height:10px;border-radius:50%;background:#2e9e6e;display:inline-block"></span>3–5 млн ₽</div>
        <div style="display:flex;align-items:center;gap:7px;margin-bottom:5px;font-size:11px"><span style="width:10px;height:10px;border-radius:50%;background:#f5a623;display:inline-block"></span>2–3 млн ₽</div>
        <div style="display:flex;align-items:center;gap:7px;font-size:11px"><span style="width:10px;height:10px;border-radius:50%;background:#e05252;display:inline-block"></span>до 2 млн ₽</div>
        <div style="font-size:10px;color:var(--ink3);margin-top:8px">${data.points.length} объектов</div>`;
    }
  } catch(e) {
    const l = document.getElementById('dotsLoader');
    if(l) l.textContent = 'Ошибка загрузки: ' + e.message;
  }
}

function setMapMode(mode,btn){
  mapMode=mode;
  document.querySelectorAll('.mode-btn').forEach(b=>b.classList.remove('on'));
  btn.classList.add('on');
  if(!mapReady){initLeafMap();return;}
  if(mode==='heat'){
    if(leafMap.hasLayer(dotGroup))leafMap.removeLayer(dotGroup);
    heatGroup.clearLayers();
    heatGroup.addTo(leafMap);
    renderHeat();
    leafMap.fitBounds(L.geoJSON(DISTRICTS_GJ).getBounds(),{padding:[30,30]});
    document.getElementById('mapLegend').style.display='block';
  }else{renderDots();}
}


