function cmpRemove(id){
  const el = document.getElementById(`cmpW${id}`);
  if(el) el.remove();
  _cmpIds = _cmpIds.filter(x => x !== id);
  document.getElementById('cmpAddBtn').style.display = '';
}

function cmpGetParams(id){
  const g  = x => document.getElementById(x);
  const di = parseInt(g(`cd_d${id}`)?.value ?? 4);
  const dist = CMP_DIST[di] || CMP_DIST[4];
  const bti  = parseInt(g(`cd_b${id}`)?.value ?? 1);
  const oti  = parseInt(g(`cd_o${id}`)?.value ?? 0);
  return {
    geo_lat:       dist.lat,
    geo_lon:       dist.lon,
    district_name: dist.name,
    building_type: CMP_BT[bti]?.v ?? 1,
    building_name: CMP_BT[bti]?.n ?? '—',
    object_type:   CMP_OT[oti]?.v ?? 1,
    object_name:   CMP_OT[oti]?.n ?? '—',
    area:          parseFloat(g(`cd_a${id}`)?.value) || 42,
    rooms:         parseInt(g(`cd_r${id}`)?.value)   || 2,
    level:         parseInt(g(`cd_f${id}`)?.value)   || 5,
    levels:        9,
    kitchen_area:  parseFloat(g(`cd_k${id}`)?.value) || 9,
    year:          2010,
    month:         6,
    listed_price:  parseFloat(g(`cd_p${id}`)?.value) || 0,
  };
}

async function doCmpAnalyze(){
  const ids = _cmpIds.filter(id => document.getElementById(`cmpW${id}`));
  if(ids.length < 2){ alert('Добавьте минимум 2 варианта'); return; }

  const show = (el, v) => document.getElementById(el).style.display = v;
  show('cmpResult','none'); show('cmpError','none'); show('cmpLoader','block');

  try {
    const results = await Promise.all(ids.map((id, pos) => {
      const p = cmpGetParams(id);
      return fetch('/analyze', {
        method:'POST', headers:{'Content-Type':'application/json'},
        body: JSON.stringify(p)
      }).then(r => r.json()).then(d => ({...d, _p:p, _pos:pos, _letter:CMP_LETTERS[pos], _color:CMP_COLORS[pos]}));
    }));

    show('cmpLoader','none');

    const fmt = n => (+n).toLocaleString('ru');

    // ── 1. Главный вывод ─────────────────────────────────────────
    // Лучший = наименьшая переплата (diff_pct) среди тех у кого есть listed_price,
    // или наименьшая цена за м² в остальных
    const withPrice = results.filter(r => r._p.listed_price > 0);
    let winner;
    if(withPrice.length >= 2){
      winner = withPrice.reduce((a,b) => a.diff_pct < b.diff_pct ? a : b);
    } else {
      winner = results.reduce((a,b) => a.price_per_sqm < b.price_per_sqm ? a : b);
    }

    // Считаем экономию победителя относительно самого дорогого
    const maxModel = Math.max(...results.map(r => r.model_price));
    const saving   = maxModel - winner.model_price;

    document.getElementById('cmpVerdict').innerHTML = `
      <div style="background:linear-gradient(135deg,#e8f5f0,#f0faf6);border-radius:16px;
        padding:22px 28px;border:1.5px solid #1a6e4a22;display:flex;align-items:center;gap:20px;flex-wrap:wrap">
        <div style="font-size:40px">⭐</div>
        <div>
          <div style="font-size:18px;font-weight:900;color:#1a6e4a;margin-bottom:4px">
            Вариант ${winner._letter} выгоднее
          </div>
          <div style="font-size:14px;color:#2c3e54;max-width:520px">
            ${winner._p.district_name}, ${winner._p.area} м², ${winner._p.rooms} комн.
            — цена по модели <b>${fmt(winner.model_price)} ₽</b>
            ${saving>0?`(выгоднее на <b>${fmt(saving)} ₽</b> по сравнению с самым дорогим)`:''}.
            ${winner._p.listed_price>0 && winner.diff_pct<0
              ? `Объявление ниже рынка на <b>${Math.abs(winner.diff_pct)}%</b> — это хорошая возможность.`
              : winner._p.listed_price>0 && winner.diff_pct<=10
              ? `Цена в объявлении соответствует рынку.`
              : ''}
          </div>
        </div>
      </div>`;

    // ── 2. Карточки вариантов ─────────────────────────────────────
    const maxPpm = Math.max(...results.map(r => r.price_per_sqm));
    document.getElementById('cmpCards').innerHTML = results.map(r => {
      const isWin = r === winner;
      const barW  = Math.round(r.price_per_sqm / maxPpm * 100);
      const diffColor = r._p.listed_price > 0
        ? (r.diff_rub > 0 ? '#c0392b' : '#1a6e4a')
        : '#637b95';
      const diffLabel = r._p.listed_price > 0
        ? `${r.diff_rub>0?'+':''}${fmt(r.diff_rub)} ₽ (${r.diff_rub>0?'+':''}${r.diff_pct}%)`
        : '—';
      return `
      <div style="background:#fff;border-radius:14px;padding:18px;flex:1;min-width:175px;
        border:2px solid ${isWin?'#1a6e4a':'var(--surf3)'};
        box-shadow:${isWin?'0 4px 20px rgba(11,122,99,.12)':'0 2px 8px rgba(0,0,0,.05)'};
        position:relative">
        ${isWin?'<div style="position:absolute;top:-10px;left:50%;transform:translateX(-50%);'+
          'background:#1a6e4a;color:#fff;font-size:10px;font-weight:700;padding:3px 12px;'+
          'border-radius:20px;white-space:nowrap">⭐ Выгоднее</div>':''}
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px">
          <div style="width:28px;height:28px;border-radius:50%;background:${r._color};color:#fff;
            font-weight:900;font-size:13px;display:flex;align-items:center;justify-content:center">
            ${r._letter}</div>
          <div style="font-size:12px;color:#637b95">${r._p.district_name}</div>
        </div>
        <div style="font-size:11px;color:#637b95;margin-bottom:2px">
          ${r._p.area} м² · ${r._p.rooms} комн. · эт.${r._p.level} · ${r._p.building_name}
        </div>
        <div style="font-size:20px;font-weight:900;color:var(--ink);margin:10px 0 2px">
          ${fmt(r.model_price)} ₽
        </div>
        <div style="font-size:12px;color:#637b95;margin-bottom:10px">
          ${fmt(r.price_per_sqm)} ₽/м²
        </div>
        <div style="background:#f0f2f5;border-radius:3px;height:4px;margin-bottom:10px;overflow:hidden">
          <div style="height:100%;width:${barW}%;background:${r._color};border-radius:3px"></div>
        </div>
        ${r._p.listed_price>0?`
        <div style="font-size:11px;padding:6px 10px;border-radius:8px;
          background:${r.diff_rub>0?'#fdf0ee':'#e8f5f0'}">
          <span style="color:#637b95">Объявление:</span>
          <b>${fmt(r._p.listed_price)} ₽</b><br>
          <span style="color:${diffColor};font-weight:700">${diffLabel}</span>
          — ${r.verdict?.title||''}
        </div>`:''}
      </div>`;
    }).join('');

    // ── 3. Сравнительная таблица SHAP ────────────────────────────
    // Собираем все уникальные факторы из всех вариантов
    const allFactorNames = [];
    results.forEach(r => (r.factors||[]).forEach(f => {
      if(!allFactorNames.includes(f.name)) allFactorNames.push(f.name);
    }));
    // Оставляем топ-6 по среднему abs(shap_rub)
    const factorRanked = allFactorNames.map(name => {
      const vals = results.map(r => {
        const f = (r.factors||[]).find(x => x.name === name);
        return f ? Math.abs(f.shap_rub) : 0;
      });
      return {name, avg: vals.reduce((a,b)=>a+b,0)/vals.length};
    }).sort((a,b) => b.avg-a.avg).slice(0,7);

    // Заголовок таблицы
    const headerCols = results.map(r =>
      `<th style="text-align:center;padding:10px 8px;font-size:12px;font-weight:700;color:#fff;
        background:${r._color};border-radius:6px">Вариант ${r._letter}</th>`
    ).join('');

    // Строки
    const tableRows = factorRanked.map(({name}) => {
      const factorData = results.map(r => (r.factors||[]).find(f => f.name === name) || null);
      const icon = factorData.find(f=>f)?.icon || '📊';

      // Находим максимальный вклад для нормировки бара
      const maxAbs = Math.max(...factorData.map(f => f ? Math.abs(f.shap_rub) : 0), 1);

      const cells = factorData.map((f, i) => {
        if(!f) return `<td style="text-align:center;padding:10px 8px;color:#ccc">—</td>`;
        const pos   = f.direction === 'pos';
        const color = pos ? '#1a6e4a' : '#c0392b';
        const sign  = pos ? '+' : '';
        const barW  = Math.round(Math.abs(f.shap_rub) / maxAbs * 80);
        return `<td style="text-align:center;padding:10px 8px">
          <div style="font-size:12px;font-weight:800;color:${color};margin-bottom:4px">
            ${sign}${fmt(f.shap_rub)} ₽</div>
          <div style="font-size:10px;color:#637b95;margin-bottom:4px">${f.value}</div>
          <div style="background:#f0f2f5;border-radius:2px;height:4px;width:80px;margin:0 auto;overflow:hidden">
            <div style="height:100%;width:${barW}%;background:${color};border-radius:2px"></div>
          </div>
        </td>`;
      }).join('');

      return `<tr style="border-bottom:1px solid #f0f2f5">
        <td style="padding:10px 12px;white-space:nowrap">
          <span style="font-size:16px;margin-right:6px">${icon}</span>
          <span style="font-size:12px;font-weight:600;color:var(--ink)">${name}</span>
        </td>
        ${cells}
      </tr>`;
    }).join('');

    document.getElementById('cmpShapTable').innerHTML = `
      <div style="background:#fff;border-radius:14px;overflow:hidden;
        box-shadow:0 2px 12px rgba(0,0,0,.06)">
        <table style="width:100%;border-collapse:collapse">
          <thead>
            <tr style="border-bottom:2px solid #f0f2f5">
              <th style="padding:12px;text-align:left;font-size:12px;color:#637b95;font-weight:600">
                Фактор</th>
              ${headerCols}
            </tr>
          </thead>
          <tbody>${tableRows}</tbody>
        </table>
      </div>`;

    // ── 4. Итоговый вывод ─────────────────────────────────────────
    const sumColors = ['#e8f5f0','#e8f0fc','#fff7e8','#f4f4fa'];
    const sumTxtCol = ['#1a6e4a','#2e7dd6','#b37a00','#555'];
    document.getElementById('cmpSummary').innerHTML = `
      <div style="background:#fff;border-radius:14px;padding:22px 24px;
        box-shadow:0 2px 12px rgba(0,0,0,.06)">
        <div style="font-size:15px;font-weight:800;margin-bottom:16px">📋 Итог</div>
        ${results.map((r,i) => {
          const isWin = r === winner;
          const top = (r.factors||[])[0];
          return `
          <div style="display:flex;gap:14px;align-items:flex-start;padding:12px 0;
            border-bottom:${i<results.length-1?'1px solid #f0f2f5':'none'}">
            <div style="width:36px;height:36px;border-radius:50%;flex-shrink:0;
              background:${sumColors[i]};color:${sumTxtCol[i]};
              display:flex;align-items:center;justify-content:center;
              font-weight:900;font-size:15px">${r._letter}</div>
            <div>
              <div style="font-size:13px;font-weight:700;margin-bottom:3px">
                ${isWin?'⭐ ':''}${r._p.district_name} · ${r._p.area} м²
              </div>
              <div style="font-size:12px;color:#637b95;line-height:1.6">
                Цена модели: <b style="color:var(--ink)">${fmt(r.model_price)} ₽</b>
                (${fmt(r.price_per_sqm)} ₽/м²).
                ${top?`Сильнее всего влияет: <b>${top.name}</b> (${top.direction==='pos'?'+':''}${fmt(top.shap_rub)} ₽).`:''}
                ${r._p.listed_price>0?`Объявление: <span style="color:${r.diff_rub>0?'#c0392b':'#1a6e4a'};font-weight:700">
                  ${r.diff_rub>0?'переплата':'экономия'} ${fmt(Math.abs(r.diff_rub))} ₽</span>.`:''}
              </div>
            </div>
          </div>`;
        }).join('')}
      </div>`;

    show('cmpResult','block');
    document.getElementById('cmpFormSection').style.display = 'none';
    window.scrollTo(0,0);

    // Сохраняем каждый вариант в историю
    results.forEach((r, i) => {
      const p = r._p;
      histSave({
        source:      'compare',
        district:    p.district_name,
        area:        p.area,
        rooms:       p.rooms,
        level:       p.level,
        levels:      p.levels || 9,
        kitchen:     p.kitchen_area,
        btype_name:  p.building_name,
        otype_name:  p.object_name,
        price:       r.model_price,
        price_sqm:   r.price_per_sqm,
        price_low:   r.price_low,
        price_high:  r.price_high,
        listed:      p.listed_price || 0,
        verdict:     r.verdict?.status || 'ok',
        verdict_title: r.verdict?.title || '',
        diff_pct:    r.diff_pct,
        diff_rub:    r.diff_rub,
        suggest:     r.suggest,
        factors:     r.factors || [],
        cmp_letter:  r._letter,
        is_winner:   r === winner,
      });
    });

  } catch(e) {
    show('cmpLoader','none');
    document.getElementById('cmpError').style.display = 'block';
    document.getElementById('cmpError').textContent = '⚠ Ошибка: ' + e.message;
  }
}

// ── ИСТОРИЯ ──────────────────────────────────────────────────────────────────

const HIST_KEY = 'predikt_history';

function histLoad(){
  try { return JSON.parse(localStorage.getItem(HIST_KEY)) || []; }
  catch{ return []; }
}

function histSave(entry){
  const list = histLoad();
  list.unshift({
    id:       Date.now(),
    ts:       new Date().toISOString(),
    ...entry
  });
  // Храним последние 100 записей
  localStorage.setItem(HIST_KEY, JSON.stringify(list.slice(0, 100)));
  // Если страница истории открыта — обновляем
  if(document.getElementById('pg-hist')?.classList.contains('on')) histRender();
}

// Состояние фильтра
let _histFilter = 'all';

function histFilter(btn, val){
  _histFilter = val;
  document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('on'));
  btn.classList.add('on');
  histRender();
}

function histRender(){
  const list    = histLoad();
  const query   = (document.getElementById('histSearch')?.value || '').toLowerCase();

  // Подсчёт статистики по всем записям (без фильтра)
  const total = list.length;
  const over  = list.filter(r => r.verdict === 'high').length;
  const fair  = list.filter(r => r.verdict === 'ok').length;
  const good  = list.filter(r => r.verdict === 'low').length;

  // KPI
  document.getElementById('hk_total').textContent = total;
  document.getElementById('hk_over').textContent  = over;
  document.getElementById('hk_fair').textContent  = fair;
  document.getElementById('hk_good').textContent  = good;

  // Кнопка очистки
  document.getElementById('histClearBtn').style.display = total > 0 ? '' : 'none';

  if(total === 0){
    document.getElementById('histEmpty').style.display    = 'block';
    document.getElementById('histBar').style.display      = 'none';
    document.getElementById('histControls').style.display = 'none';
    document.getElementById('histList').innerHTML         = '';
    return;
  }

  document.getElementById('histEmpty').style.display    = 'none';
  document.getElementById('histControls').style.display = '';

  // Прогресс-бар
  if(total > 0){
    document.getElementById('histBar').style.display = 'block';
    const pOver = Math.round(over/total*100);
    const pFair = Math.round(fair/total*100);
    const pGood = 100 - pOver - pFair;
    document.getElementById('histBarTrack').innerHTML =
      (over>0?`<div style="flex:${over};background:var(--red2)"></div>`:'') +
      (fair>0?`<div style="flex:${fair};background:var(--green2)"></div>`:'') +
      (good>0?`<div style="flex:${good};background:var(--blue2)"></div>`:'');
    document.getElementById('histBarLegend').innerHTML =
      `<div class="hbar-label"><div class="hbar-dot" style="background:var(--red2)"></div>Завышены — ${pOver}%</div>
       <div class="hbar-label"><div class="hbar-dot" style="background:var(--green2)"></div>Справедливые — ${pFair}%</div>
       <div class="hbar-label"><div class="hbar-dot" style="background:var(--blue2)"></div>Выгодные — ${pGood}%</div>`;
  }

  // Фильтрация + поиск
  const filtered = list.filter(r => {
    const matchFilter =
      _histFilter === 'all' ||
      (_histFilter === 'high' && r.verdict === 'high') ||
      (_histFilter === 'ok'   && r.verdict === 'ok')   ||
      (_histFilter === 'low'  && r.verdict === 'low');

    if(!matchFilter) return false;
    if(!query) return true;

    const text = [r.district, r.area, r.rooms, r.price].join(' ').toLowerCase();
    return text.includes(query);
  });

  // Рендер списка
  const listEl = document.getElementById('histList');

  if(filtered.length === 0){
    listEl.innerHTML = `<div style="text-align:center;padding:48px;color:#637b95;font-size:14px">
      Ничего не найдено по вашему запросу</div>`;
    return;
  }

  const BT = {0:'другой тип',1:'панель',2:'монолит',3:'кирпич',4:'блок',5:'дерево'};

  listEl.innerHTML = filtered.map((r, i) => {
    const dt = new Date(r.ts);
    const dateStr = dt.toLocaleDateString('ru',{day:'2-digit',month:'2-digit',year:'numeric'}) +
                    ' в ' + dt.toLocaleTimeString('ru',{hour:'2-digit',minute:'2-digit'});

    const badge = r.verdict === 'high'
      ? `<div class="hi-badge badge-over">🔴 Завышена${r.diff_pct?` +${Math.abs(r.diff_pct)}%`:''}</div>`
      : r.verdict === 'low'
      ? `<div class="hi-badge badge-under">🔵 Выгодная${r.diff_pct?` ${r.diff_pct}%`:''}</div>`
      : `<div class="hi-badge badge-fair">🟢 Справедливая</div>`;

    const rooms = r.rooms === 0 ? 'Студия' : r.rooms + ' комн';
    const sourceIcon = r.source === 'check' ? '🔍' : '🧮';

    return `<div class="hitem" style="position:relative;cursor:pointer"
        onclick="histShowModal(${r.id})">
      <div class="hi-num" style="font-size:13px;color:#aaa">${String(i+1).padStart(2,'0')}</div>
      <div class="hi-main">
        <div class="hi-title">
          ${sourceIcon} ${r.district}, ${r.area} м²
        </div>
        <div class="hi-meta">
          ${rooms} · эт. ${r.level}${r.levels?'/'+r.levels:''} · ${dateStr}
        </div>
      </div>
      <div class="hi-price">
        <div class="hi-pv">${(+r.price).toLocaleString('ru')} ₽</div>
        ${badge}
        ${r.listed>0?`<div style="font-size:11px;color:#637b95;margin-top:3px">
          Объявление: ${(+r.listed).toLocaleString('ru')} ₽</div>`:''}
      </div>
      <button onclick="event.stopPropagation();histDelete(${r.id})" title="Удалить"
        style="position:absolute;top:12px;right:12px;background:none;border:none;
               cursor:pointer;color:#ddd;font-size:16px;padding:4px;line-height:1"
        onmouseover="this.style.color='var(--red2)'" onmouseout="this.style.color='#ddd'">✕</button>
    </div>`;
  }).join('');
}

function histDelete(id){
  const list = histLoad().filter(r => r.id !== id);
  localStorage.setItem(HIST_KEY, JSON.stringify(list));
  histRender();
}

function histClear(){
  if(!confirm('Очистить всю историю оценок?')) return;
  localStorage.removeItem(HIST_KEY);
  histRender();
}

// ── МОДАЛЬНОЕ ОКНО ДЕТАЛИ ─────────────────────────────────────────────────

function histShowModal(id){
  const list = histLoad();
  const r = list.find(x => x.id === id);
  if(!r) return;

  const fmt = n => (+n||0).toLocaleString('ru') + ' ₽';
  const fmtN = n => (+n||0).toLocaleString('ru');

  // Заголовок и бейдж источника
  const sourceLabel = r.source === 'estimate' ? '🧮 Оценка квартиры'
                    : r.source === 'check'    ? '🔍 Проверка объявления'
                    :                           '⚖️ Сравнение вариантов';

  const verdictColor = r.verdict === 'high' ? '#c0392b'
                     : r.verdict === 'low'  ? '#1a6e4a'
                     : '#2e7dd6';
  const verdictBg    = r.verdict === 'high' ? '#fdf0ee'
                     : r.verdict === 'low'  ? '#e8f5f0'
                     : '#eef4fd';
  const verdictIcon  = r.verdict === 'high' ? '⚠️'
                     : r.verdict === 'low'  ? '✅' : '👍';

  const dt = new Date(r.ts);
  const dateStr = dt.toLocaleDateString('ru',{day:'2-digit',month:'2-digit',year:'numeric'})
                + ' в ' + dt.toLocaleTimeString('ru',{hour:'2-digit',minute:'2-digit'});

  // SHAP факторы
  let factorsHtml = '';
  if(r.factors && r.factors.length > 0){
    factorsHtml = `
    <div style="margin-top:20px">
      <div style="font-size:13px;font-weight:700;color:#1a1a2e;margin-bottom:10px">🔬 SHAP — вклад факторов</div>
      ${r.factors.slice(0,6).map(f => {
        const pos   = f.direction === 'pos';
        const color = pos ? '#1a6e4a' : '#c0392b';
        const sign  = pos ? '+' : '';
        const arrow = pos ? '▲' : '▼';
        const rub   = Math.abs(+f.shap_rub||0).toLocaleString('ru');
        return `<div style="display:flex;align-items:center;gap:10px;padding:7px 0;border-bottom:1px solid #f0f2f5">
          <span style="font-size:17px;width:24px;text-align:center">${f.icon||'📊'}</span>
          <div style="flex:1;min-width:0">
            <div style="font-size:12px;font-weight:600;color:#1a1a2e">${f.name}
              <span style="font-weight:400;color:#637b95;margin-left:4px">${f.value||''}</span></div>
            <div style="background:#f0f2f5;border-radius:3px;height:4px;margin-top:4px;overflow:hidden">
              <div style="height:100%;width:${f.bar||0}%;background:${color};border-radius:3px"></div></div>
          </div>
          <div style="font-size:12px;font-weight:800;color:${color};min-width:90px;text-align:right">
            ${arrow} ${sign}${rub} ₽</div>
        </div>`;
      }).join('')}
    </div>`;
  }

  // Строка сравнения (если есть listed)
  let diffHtml = '';
  if(r.listed > 0){
    const diffColor = r.diff_rub > 0 ? '#c0392b' : '#1a6e4a';
    const diffSign  = r.diff_rub > 0 ? '+' : '';
    diffHtml = `
    <div style="background:${verdictBg};border-radius:10px;padding:12px 16px;margin-top:12px">
      <div style="font-size:13px;font-weight:700;color:${verdictColor};margin-bottom:6px">
        ${verdictIcon} ${r.verdict_title||'Результат проверки'}</div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;font-size:12px">
        <span style="color:#637b95">Объявление:</span>
        <b>${fmt(r.listed)}</b>
        <span style="color:#637b95">Разница:</span>
        <b style="color:${diffColor}">${diffSign}${fmtN(r.diff_rub)} ₽ (${diffSign}${r.diff_pct||0}%)</b>
        ${r.suggest?`<span style="color:#637b95">Предложить:</span><b style="color:#1a6e4a">${fmt(r.suggest)}</b>`:''}
      </div>
    </div>`;
  }

  // Метка сравнения
  const cmpBadge = r.cmp_letter
    ? `<span style="padding:2px 8px;background:#1a6e4a;color:#fff;border-radius:12px;
        font-size:10px;font-weight:700;margin-left:8px">Вариант ${r.cmp_letter}${r.is_winner?' ⭐':''}</span>`
    : '';

  document.getElementById('histModalBody').innerHTML = `
    <div style="display:flex;align-items:center;gap:8px;margin-bottom:16px;flex-wrap:wrap">
      <span style="font-size:12px;font-weight:700;padding:4px 12px;background:#f0f2f5;
        border-radius:20px;color:#637b95">${sourceLabel}</span>
      ${cmpBadge}
      <span style="font-size:11px;color:#aaa;margin-left:auto">${dateStr}</span>
    </div>

    <div style="font-size:20px;font-weight:900;color:#1a1a2e;margin-bottom:2px">
      ${r.district}, ${r.area} м²
    </div>
    <div style="font-size:13px;color:#637b95;margin-bottom:16px">
      ${r.rooms} комн. · эт. ${r.level}${r.levels?'/'+r.levels:''} · ${r.btype_name||'—'} · ${r.otype_name||'—'}
      ${r.kitchen?` · кухня ${r.kitchen} м²`:''}
    </div>

    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:4px">
      <div style="background:#f8fafb;border-radius:10px;padding:12px;text-align:center">
        <div style="font-size:17px;font-weight:900;color:#1a1a2e">${fmtN(r.price)}</div>
        <div style="font-size:10px;color:#637b95;margin-top:2px">₽ по модели</div>
      </div>
      <div style="background:#f8fafb;border-radius:10px;padding:12px;text-align:center">
        <div style="font-size:17px;font-weight:900;color:#1a1a2e">${fmtN(r.price_sqm)}</div>
        <div style="font-size:10px;color:#637b95;margin-top:2px">₽/м²</div>
      </div>
      <div style="background:#f8fafb;border-radius:10px;padding:12px;text-align:center">
        <div style="font-size:12px;font-weight:700;color:#637b95">${fmtN(r.price_low)}</div>
        <div style="font-size:10px;color:#aaa">— диапазон —</div>
        <div style="font-size:12px;font-weight:700;color:#637b95">${fmtN(r.price_high)}</div>
      </div>
    </div>

    ${diffHtml}
    ${factorsHtml}
  `;

  document.getElementById('histModal').style.display = 'flex';
}

function histCloseModal(){
  document.getElementById('histModal').style.display = 'none';
}

// Вызывается при переходе на вкладку
function histOpen(){ histRender(); }

// init

// ── MAP POINTS: fetch viewport → canvas render ────────────────────────────

let _cvs = null, _ctx = null, _pop = null, _reqTimeout = null;
let _lastBounds = null, _drawing = false;

const _BT = {0:'Другой',1:'Панельный',2:'Монолитный',3:'Кирпичный',4:'Блочный',5:'Деревянный'};
const _OT = {0:'Неизвестно',1:'Вторичка',2:'Новостройка'};
function _col(p){ return p>5000000?'#1a6e4a':p>3000000?'#2e9e6e':p>2000000?'#f5a623':'#e05252'; }

// Рисует массив точек на canvas
function _drawPts(pts){
  if(!_cvs) return;
  const size = leafMap.getSize();
  _cvs.width = size.x; _cvs.height = size.y;
  _ctx.clearRect(0,0,size.x,size.y);

  const zoom = leafMap.getZoom();
  const r = zoom<=7?2.5:zoom<=9?3:zoom<=11?3.5:zoom<=13?4.5:5.5;

  // Группируем по цвету — 4 прохода
  const COLS=['#e05252','#f5a623','#2e9e6e','#1a6e4a'];
  const grp=[[],[],[],[]];
  pts.forEach(p=>{
    const gi=p.price>5000000?3:p.price>3000000?2:p.price>2000000?1:0;
    const px=leafMap.latLngToContainerPoint([p.lat,p.lon]);
    grp[gi].push(px);
  });
  COLS.forEach((c,i)=>{
    if(!grp[i].length) return;
    _ctx.beginPath(); _ctx.fillStyle=c;
    grp[i].forEach(px=>{ _ctx.moveTo(px.x+r,px.y); _ctx.arc(px.x,px.y,r,0,Math.PI*2); });
    _ctx.fill();
  });
}

// Загружает точки с сервера по текущему viewport
async function _fetchAndDraw(){
  if(!leafMap || _drawing) return;
  _drawing = true;

  const bounds = leafMap.getBounds();
  const zoom   = leafMap.getZoom();

  // Не перезапрашиваем если bbox почти не изменился
  const b = [bounds.getSouth(),bounds.getNorth(),bounds.getWest(),bounds.getEast()].map(x=>x.toFixed(3)).join(',');
  if(b === _lastBounds){ _drawing=false; return; }
  _lastBounds = b;

  const loader = document.getElementById('dotsLoader');
  if(loader) loader.textContent = '⏳ Загружаем...';

  try{
    const params = new URLSearchParams({
      minLat: bounds.getSouth().toFixed(5),
      maxLat: bounds.getNorth().toFixed(5),
      minLon: bounds.getWest().toFixed(5),
      maxLon: bounds.getEast().toFixed(5),
      zoom:   zoom
    });
    const resp = await fetch('/points?' + params);
    const data = await resp.json();

    if(data.error){ console.error('/points error:', data.error); _drawing=false; return; }

    _drawPts(data.points);

    if(loader) loader.textContent = '✅ '+data.total.toLocaleString('ru')+' объектов (zoom '+zoom+')';

    const leg = document.getElementById('mapLegend');
    if(leg){
      leg.style.display='block';
      leg.innerHTML=
        '<div style="font-size:11px;font-weight:700;margin-bottom:6px">Цена объекта</div>'+
        '<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px;font-size:11px"><span style="width:10px;height:10px;border-radius:50%;background:#1a6e4a;display:inline-block"></span>от 5 млн ₽</div>'+
        '<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px;font-size:11px"><span style="width:10px;height:10px;border-radius:50%;background:#2e9e6e;display:inline-block"></span>3–5 млн ₽</div>'+
        '<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px;font-size:11px"><span style="width:10px;height:10px;border-radius:50%;background:#f5a623;display:inline-block"></span>2–3 млн ₽</div>'+
        '<div style="display:flex;align-items:center;gap:6px;font-size:11px"><span style="width:10px;height:10px;border-radius:50%;background:#e05252;display:inline-block"></span>до 2 млн ₽</div>';
    }

    // Сохраняем последние точки для клика
    _cvs._pts = data.points;

  } catch(e){ console.error('fetch /points:', e); }
  _drawing = false;
}

// Throttle 250мс
function _throttledFetch(){
  clearTimeout(_reqTimeout);
  _reqTimeout = setTimeout(_fetchAndDraw, 250);
}

// Клик по canvas — ближайшая точка
function _setupClick(){
  _cvs.addEventListener('click', function(e){
    const pts = _cvs._pts; if(!pts||!pts.length) return;
    const rect = _cvs.getBoundingClientRect();
    const mx=e.clientX-rect.left, my=e.clientY-rect.top;
    let best=null, bestD=15*15;
    pts.forEach(p=>{
      const px=leafMap.latLngToContainerPoint([p.lat,p.lon]);
      const d=(px.x-mx)**2+(px.y-my)**2;
      if(d<bestD){bestD=d;best=p;}
    });
    if(!best) return;

    const col=_col(best.price);
    const ppm=best.area>0?Math.round(best.price/best.area):0;

    if(!_pop){
      _pop=document.createElement('div');
      _pop.style.cssText='position:absolute;z-index:500;background:#fff;border-radius:12px;'+
        'box-shadow:0 4px 24px rgba(0,0,0,.18);padding:14px 18px;min-width:200px;'+
        'font-family:Geologica,sans-serif;font-size:12px;pointer-events:auto';
      document.getElementById('leafmap').appendChild(_pop);
    }
    _pop.innerHTML=
      '<div style="font-size:18px;font-weight:900;color:'+col+'">'+best.price.toLocaleString('ru')+' ₽</div>'+
      '<div style="color:#888;font-size:11px;margin-bottom:10px">≈ '+ppm.toLocaleString('ru')+' ₽/м²</div>'+
      '<div style="line-height:2.1">'+
      '📐 Площадь: <b>'+best.area+' м²</b><br>'+
      '🛏 Комнат: <b>'+best.rooms+'</b><br>'+
      '🍳 Кухня: <b>'+best.kit+' м²</b><br>'+
      '🏢 Этаж: <b>'+best.level+'</b><br>'+
      '🏛 Тип: <b>'+best.bt+'</b><br>'+
      '🏗 Рынок: <b>'+best.ot+'</b>'+
      '</div>'+
      '<div style="margin-top:10px;font-size:10px;color:#bbb;cursor:pointer;text-align:right"'+
      ' id="_popClose">✕ закрыть</div>';

    let lx=mx+14, ly=my-10;
    if(lx+220>_cvs.width)  lx=mx-224;
    if(ly+230>_cvs.height) ly=_cvs.height-234;
    _pop.style.left=lx+'px'; _pop.style.top=ly+'px'; _pop.style.display='block';
  });
  leafMap.on('movestart',()=>{ if(_pop) _pop.style.display='none'; });

  // Закрыть попап по кнопке
  document.addEventListener('click', function(e){
    if(e.target && e.target.id==='_popClose'){ if(_pop) _pop.style.display='none'; }
  });
}

function loadDBPoints(){
  if(!leafMap) return;

  // Убираем старое
  if(_cvs){ _cvs.remove(); _cvs=null; _ctx=null; }
  if(_pop){ _pop.remove(); _pop=null; }
  if(window._cluster){ leafMap.removeLayer(window._cluster); window._cluster=null; }
  leafMap.off('moveend zoomend', _throttledFetch);
  _lastBounds = null;

  const mapEl = document.getElementById('leafmap');

  // Создаём canvas
  _cvs = document.createElement('canvas');
  _cvs.style.cssText='position:absolute;top:0;left:0;z-index:400;pointer-events:auto;cursor:crosshair';
  mapEl.appendChild(_cvs);
  _ctx = _cvs.getContext('2d');

  _setupClick();

  // Перерисовываем canvas при pan без нового fetch (моментально)
  leafMap.on('move', function(){
    if(_cvs._pts) _drawPts(_cvs._pts);
  });

  // Новый fetch при остановке или смене зума
  leafMap.on('moveend zoomend', _throttledFetch);

  // Первый запрос
  _fetchAndDraw();
}
